const [answers, setAnswers] = useState({ isResident: null, hasChildren: null, income: null });
const [showResult, setShowResult] = useState(false);

const isEligible = answers.isResident === 'yes' && answers.hasChildren === 'yes' && answers.income === 'under-threshold';

return (
  <GoabOneColumnLayout>
    <GoabPageBlock width="704px">
      <h1>Check your eligibility</h1>
      <p>Answer a few questions to see if you may qualify for the child care subsidy.</p>

      {!showResult ? (
        <>
          <GoabRadioGroup name="isResident" onChange={(_, value) => setAnswers({...answers, isResident: value})}>
            <GoabRadioItem value="yes" label="Yes" />
            <GoabRadioItem value="no" label="No" />
          </GoabRadioGroup>
          {/* Additional questions */}
          <GoabButton onClick={() => setShowResult(true)}>Check eligibility</GoabButton>
        </>
      ) : (
        <>
          {isEligible ? (
            <GoabCallout type="success" heading="You may be eligible">
              Based on your answers, you may qualify. Start your application to confirm.
            </GoabCallout>
          ) : (
            <GoabCallout type="information" heading="You may not be eligible">
              Based on your answers, you may not qualify. Contact us if you have questions.
            </GoabCallout>
          )}
          <GoabButton onClick={() => navigate('/apply')}>Start application</GoabButton>
        </>
      )}
    </GoabPageBlock>
  </GoabOneColumnLayout>
);
